let LtkReveal(s) =
  event LtkReveal(pk(s)); out(s)

/* One-time CA setup and unbounded sessions of A and B. */
process:
new ~skCA; out(pk(~skCA)); event CAInit(pk(~skCA));
(
  !CA(~skCA)
|
  !(
    new ~skA; out(pk(~skA));
    new ~skB; out(pk(~skB));
    (
        A(~skA, pk(~skB), pk(~skCA))
      | B(~skB, pk(~skB), pk(~skCA))
      | LtkReveal(~skA)
      | LtkReveal(~skB)
    )
  )
)

