/* Sanity: CA setup is reachable. */
lemma ca_setup_executable:
  exists-trace
  "Ex pkCA #i. CAInit(pkCA) @ i"

/* Executability: an honest run where B accepts a token exists. */
lemma executability:
  exists-trace
  "Ex pkA pkB t r s e #i.
     TokenAccepted(pkA, pkB, t, r, s, e) @ i"

/* Secrecy of encData intended for pkB, unless pkB's long-term key is revealed. */
lemma secrecy_encData_for_B:
  "All pkB e #i.
      SecretFor(pkB, e) @ i
      ==> not (Ex #j. K(e) @ j)
          | (Ex #r. LtkReveal(pkB) @ r)"

/* Origin authentication at B: if B accepts and A's key is not revealed, then some A issued the same token earlier. */
lemma origin_authentication_B:
  "All pkA pkB t r s e #i.
      TokenAccepted(pkA, pkB, t, r, s, e) @ i
      ==>
        (Ex #j. TokenIssued(pkA, pkB, t, r, s, e) @ j & j < i)
        | (Ex #r. LtkReveal(pkA) @ r)"

end
